/* ═══════════════════════════════════════════════
     CIRUGÍA ORTOPÉDICA Y TRAUMATOLOGÍA
   ARCHIVO 2 DE 3 — Preguntas 101-200
   Temas: Luxaciones, lesiones traumáticas e
          inflamatorias de partes blandas,
          sistema nervioso periférico
   Basado en: Manual   Traumatología y Cirugía
              Ortopédica, 10.ª edición

   DIFICULTAD: easy | medium | hard
   RESPUESTA:  0=A  1=B  2=C  3=D
═══════════════════════════════════════════════ */
var ENURM_CIRUGIA2 = [
  {id:'cir2_1',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la luxación glenohumeral más frecuente?',opts:['Posterior','Inferior (luxatio erecta)','Anterior (subcoracoidea)','Superior'],ans:2,exp:'<b>Corre :</b> La luxación glenohumeral anterior (subcoracoidea) es la más frecuente, representando más del 90% de todas las luxaciones de hombro. Se produce por caída sobre la mano con el brazo en abducción y rotación externa. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_2',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué lesión ósea de la cabeza humeral es característica de la luxación anterior de hombro?',opts:['Fractura de Hill-Sachs','Fractura de Bankart','Fractura de Neer tipo II','Fractura de la glenoide posterior'],ans:0,exp:'<b>Corre :</b> La lesión de Hill-Sachs es una fractura por impactación del segmento posterolateral de la cabeza humeral que se produce cuando ésta choca contra el borde glenoideo anterior durante la luxación anterior de hombro. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_3',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué lesión del labrum glenoideo es más frecuente en la luxación anterior de hombro recidivante?',opts:['Lesión SLAP','Lesión de Bankart (desinserción anteroinferior del labrum glenoideo)','Lesión de Hills-Sachs grande','Rotura del manguito de los rotadores'],ans:1,exp:'<b>Corre :</b> La lesión de Bankart consiste en la desinserción anteroinferior del labrum glenoideo de la glenoides, y es la lesión más característica de la luxación glenohumeral anterior recidivante (junto con la lesión de Hill-Sachs). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_4',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué nervio se lesiona con mayor frecuencia en la luxación anterior de hombro?',opts:['Nervio radial','Nervio musculocutáneo','Nervio axilar (circunflejo)','Nervio supraescapular'],ans:2,exp:'<b>Corre :</b> El nervio axilar (circunflejo) es el nervio más frecuentemente lesionado en la luxación glenohumeral anterior, por su íntima relación con el cuello quirúrgico del húmero. Produce déficit del deltoides y anestesia en la cara lateral del hombro. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_5',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el fa r predi r más importante de recidiva tras una primera luxación glenohumeral anterior?',opts:['Sexo femenino','Edad joven en el momento de la primera luxación (menor de 20-25 años)','Mecanismo traumático de alta energía','Lesión de Bankart ósea asociada'],ans:1,exp:'<b>Corre :</b> La edad joven en el momento de la primera luxación es el fa r predi r más importante de recidiva. Los menores de 20-25 años tienen tasas de recidiva superiores al 80-90% si se tratan de forma conservadora. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_6',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de la luxación glenohumeral anterior recidivante que impide la actividad deportiva?',opts:['Rehabilitación intensiva del manguito rotador','Artrodesis glenohumeral','Reconstrucción ligamentosa artroscópica (Bankart artroscópico)','Artroplastia total de hombro'],ans:2,exp:'<b>Corre :</b> La reconstrucción artroscópica del Bankart (reparación del labrum y ligamento glenohumeral inferior) es el tratamiento de elección en pacientes jóvenes con luxación recidivante que desean reanudar su actividad deportiva. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_7',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué ligamento se lesiona en los esguinces acromioclaviculares grados III-VI?',opts:['Ligamento coracoclavicular','Ligamento acromiocoracoideo','Ligamento glenohumeral superior','Ligamento esternoclavicular'],ans:0,exp:'<b>Corre :</b> En las lesiones acromioclaviculares de grado III o mayor, además de la lesión del ligamento acromioclavicular, se produce lesión del ligamento coracoclavicular (trapezoide y conoide), lo que condiciona la inestabilidad vertical de la clavícula. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_8',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento de la luxación acromioclavicular de grado I-II?',opts:['Cirugía inmediata','Tratamiento conservador (inmovilización y analgesia)','Reducción abierta y tornillos coracoclaviculares','Artrodesis acromioclavicular'],ans:1,exp:'<b>Corre :</b> Las luxaciones acromioclaviculares de grado I y II (sin lesión completa del ligamento coracoclavicular) se tratan de forma conservadora con inmovilización y analgesia. El grado III puede tratarse conservador o quirúrgicamente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_9',type:'mc',diff:'medium',sub:'cirugia',text:'¿Hacia qué lado suele luxarse la cadera en los traumatismos de alta energía (impa  sobre el tablero del salpicadero)?',opts:['Anterior','Posterior','Obturatriz','Isquiática'],ans:1,exp:'<b>Corre :</b> La luxación posterior de cadera es la más frecuente y se produce típicamente por impa  sobre el tablero del salpicadero (dashboard injury) con la cadera y la rodilla en flexión. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_10',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la urgencia principal en la luxación de cadera y cuál es su consecuencia si no se trata precozmente?',opts:['Lesión del nervio femoral; parálisis del cuádriceps','Reducción urgente; necrosis avascular de la cabeza femoral si se demora >6 horas','Hemorragia retroperitoneal; inestabilidad hemodinámica','Lesión de la arteria iliaca; isquemia del miembro'],ans:1,exp:'<b>Corre :</b> La luxación de cadera es una emergencia ortopédica. Si no se reduce de forma precoz (idealmente antes de 6 horas), el riesgo de necrosis avascular de la cabeza femoral aumenta marcadamente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_11',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué nervio se lesiona con mayor frecuencia en la luxación posterior de cadera?',opts:['Nervio femoral','Nervio obturador','Nervio ciático','Nervio glúteo superior'],ans:2,exp:'<b>Corre :</b> El nervio ciático, especialmente su división peronea, es el nervio más frecuentemente lesionado en la luxación posterior de cadera, produciendo paresia/parálisis de la dorsiflexión del pie (pie caído). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_12',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la luxación de codo más frecuente?',opts:['Anterior','Medial','Posterior','Lateral'],ans:2,exp:'<b>Corre :</b> La luxación posterior de codo es la más frecuente, producida habitualmente por caída sobre la mano con el codo en extensión. En el niño debe descartarse siempre fractura supracondílea asociada. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_13',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la tríada terrible del codo?',opts:['Luxación de codo + fractura de coronoides + rotura del ligamento colateral lateral','Fractura supracondílea + lesión nerviosa + lesión vascular','Fractura de olécranon + luxación + fractura radial','Luxación de codo + fractura del capitelum + lesión del tendón distal del bíceps'],ans:0,exp:'<b>Corre :</b> La tríada terrible del codo consiste en luxación posterior de codo + fractura de la coronoides + fractura de la cabeza radial. Es una lesión muy inestable que requiere cirugía. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_14',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la luxación de carpo más frecuente?',opts:['Luxación del semilunar','Luxación perilunar','Luxación del escafoides','Luxación de la articulación de la muñeca completa'],ans:1,exp:'<b>Corre :</b> La luxación perilunar del carpo (y la luxación del semilunar como estadio final) son las luxaciones del carpo más frecuentes. La perilunar es la más común; si progresa, el semilunar se luxa volarmente. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_15',type:'mc',diff:'medium',sub:'cirugia',text:'¿En la luxación del semilunar, qué estructura nerviosa puede comprimirse?',opts:['Nervio cubital en el canal de Guyón','Nervio mediano en el canal del carpo','Nervio radial superficial','Nervio interóseo posterior'],ans:1,exp:'<b>Corre :</b> En la luxación del semilunar, el semilunar migra volarmente y puede comprimir el nervio mediano en el canal del carpo, produciendo síndrome del túnel carpiano agudo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_16',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la luxación de rótula más frecuente y hacia dónde se produce?',opts:['Luxación medial por hiperflexión','Luxación lateral por valgo y contracción cuadricipital','Luxación superior por extensión forzada','Luxación anterior por traumatismo dire '],ans:1,exp:'<b>Corre :</b> La luxación lateral de rótula es la más frecuente. Se produce por valgo de rodilla y contracción cuadricipital que arrastra la rótula hacia afuera. Se asocia a lesión del retináculo medial y puede producir fracturas osteocondrales. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_17',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la estructura con mayor riesgo de lesión en la luxación de rodilla?',opts:['Nervio ciático','Nervio peroneo','Arteria poplítea','Tendón poplíteo'],ans:2,exp:'<b>Corre :</b> La arteria poplítea es la estructura con mayor riesgo de lesión en la luxación de rodilla, por su fijación proximal y distal. La lesión arterial es una emergencia vascular. El nervio peroneo también puede lesionarse. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_18',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tipo de esguince de tobillo más frecuente?',opts:['Esguince del complejo ligamentoso medial (deltoideo)','Esguince del ligamento sindesmal','Esguince del complejo ligamentoso lateral','Esguince simultáneo medial y lateral'],ans:2,exp:'<b>Corre :</b> El esguince del complejo ligamentoso lateral es el más frecuente y se produce por inversión forzada del tobillo. Afecta en orden al peroneoastragalino anterior, peroneocalcáneo y peroneoastragalino posterior. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_19',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué ligamento del tobillo se lesiona primero en los esguinces por inversión?',opts:['Ligamento peroneocalcáneo','Ligamento peroneoastragalino posterior','Ligamento peroneoastragalino anterior','Ligamento deltoideo'],ans:2,exp:'<b>Corre :</b> En los esguinces por inversión, los ligamentos se lesionan secuencialmente: primero el peroneoastragalino anterior, luego el peroneocalcáneo y finalmente el peroneoastragalino posterior (en los más graves). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_20',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué debe descartarse siempre cuando un paciente tiene dolor y tumefacción en la cara medial del tobillo tras un esguince?',opts:['Rotura del tendón de Aquiles','Fractura de peroné proximal (fractura de Maisonneuve)','Fractura de calcáneo','Luxación del tendón peroneo'],ans:1,exp:'<b>Corre :</b> Cuando un paciente presenta dolor y tumefacción en la cara medial del tobillo, es necesario descartar una fractura de peroné proximal asociada (fractura de Maisonneuve) mediante radiografías que visualicen el peroné en toda su longitud. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_21',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento inicial del esguince de tobillo leve?',opts:['Cirugía inmediata','Yeso inguinopédico durante 6 semanas','Vendaje compresivo, reposo, elevación, frío local y antiinflamatorios (RICE)','Artrodesis de tobillo'],ans:2,exp:'<b>Corre :</b> El tratamiento inicial del esguince de tobillo consiste en las medidas RICE: vendaje compresivo, reposo, elevación del miembro, frío local y antiinflamatorios (AINE). En los casos más graves se añade inmovilización con férula o tobillera estabilizadora. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_22',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la causa más frecuente de hombro doloroso?',opts:['Artritis reumatoide del hombro','Capsulitis adhesiva','Patología del espacio subacromial (síndrome de rozamiento subacromial)','Artropatía del manguito de los rotadores'],ans:2,exp:'<b>Corre :</b> La patología del espacio subacromial (síndrome de rozamiento subacromial) constituye la causa más frecuente de hombro doloroso. El manguito de los rotadores es la estructura más afectada. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_23',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué tendones forman el manguito de los rotadores de anterior a posterior?',opts:['Deltoides, supraespinoso, infraespinoso y redondo menor','Subescapular, supraespinoso, infraespinoso y redondo menor','Supraespinoso, subescapular, redondo mayor e infraespinoso','Bíceps, supraespinoso, infraespinoso y subescapular'],ans:1,exp:'<b>Corre :</b> El manguito de los rotadores está formado por los tendones del subescapular, supraespinoso, infraespinoso y redondo menor (de anterior a posterior). El tendón de la porción larga del bíceps se considera funcionalmente parte del manguito. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_24',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la función principal del manguito de los rotadores?',opts:['Elevación del brazo por encima de la horizontal','Mantener centrada la cabeza humeral sobre la glenoides durante los movimientos del hombro','Estabilizar la escápula en la pared torácica','Controlar la rotación del tronco'],ans:1,exp:'<b>Corre :</b> La principal función del manguito de los rotadores es mantener centrada la cabeza humeral sobre la glenoides durante los movimientos del hombro. También participa en la abducción y las rotaciones del brazo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_25',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el signo clínico de Neer y qué confirma?',opts:['Dolor a la abducción activa máxima; confirma lesión del supraespinoso','Dolor a la elevación pasiva máxima del hombro al chocar el manguito con el acromion anteroinferior; confirma el síndrome subacromial','Incapacidad de bajar el brazo lentamente desde 90°; confirma rotura completa del manguito','Dolor a la rotación interna máxima; confirma capsulitis adhesiva'],ans:1,exp:'<b>Corre :</b> El signo de Neer es el dolor que aparece con la elevación pasiva máxima del hombro al chocar el manguito con la parte anteroinferior del acromion. La desaparición del dolor tras infiltración subacromial con anestésico (test de Neer) confirma el síndrome subacromial. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_26',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el arco doloroso típico del síndrome subacromial?',opts:['De 0 a 30° de elevación','De 30° a 60° de elevación','De 80° a 120° de elevación (al bajar activamente el brazo)','De 120° a 180° de elevación máxima'],ans:2,exp:'<b>Corre :</b> En el síndrome de rozamiento subacromial, es típico que el dolor aumente cuando el paciente baja activamente el brazo, especialmente entre los 120° y los 80° de elevación (arco doloroso). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_27',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento conservador inicial del síndrome de rozamiento subacromial?',opts:['Inmovilización con cabestrillo durante 6 semanas','Analgésicos, antiinflamatorios, reposo breve y rehabilitación (recuperar movilidad y fortalecer manguito)','Infiltración con corticoides como primera medida','Cirugía artroscópica inmediata'],ans:1,exp:'<b>Corre :</b> El tratamiento conservador inicial del síndrome de rozamiento subacromial consiste en analgésicos, antiinflamatorios, un periodo breve de reposo e inicio de programa de rehabilitación (recuperar movilidad y fortalecer la mitad inferior del manguito). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_28',type:'mc',diff:'medium',sub:'cirugia',text:'¿En qué consiste la acromioplastia artroscópica?',opts:['Extirpación completa del acromion','Resección de aproximadamente 1 cm del margen anteroinferior del acromion por vía artroscópica','Osteotomía del acromion con descompresión','Artrodesis acromioclavicular con descompresión'],ans:1,exp:'<b>Corre :</b> La acromioplastia artroscópica consiste en resecar aproximadamente 1 cm del margen anteroinferior del acromion por vía artroscópica, ampliando el espacio subacromial. Se realiza en pacientes sin rotura del manguito que no responden al tratamiento conservador durante 3-6 meses. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_29',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la tendinitis calcificante del hombro?',opts:['Calcificación del ligamento coracoclavicular','Calcificación del ligamento glenohumeral inferior','Depósito de calcio en el espesor de los tendones del manguito de los rotadores','Calcificación de la articulación acromioclavicular'],ans:2,exp:'<b>Corre :</b> La tendinitis calcificante consiste en la formación de un depósito de calcio en el espesor de los tendones del manguito de los rotadores. Produce dolor muy intenso de predominio nocturno que puede durar días o semanas, pero es un proceso autolimitado. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_30',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué caracteriza clínicamente a la capsulitis adhesiva del hombro (hombro congelado)?',opts:['Solo limitación de la movilidad activa, con movilidad pasiva conservada','Dolor intenso seguido de rigidez del hombro en todos los planos, con limitación tanto activa como pasiva','Solo dolor nocturno sin limitación de la movilidad','Dolor a la movilidad activa sin dolor en reposo'],ans:1,exp:'<b>Corre :</b> La capsulitis adhesiva se caracteriza por un periodo de dolor bastante intenso seguido por el desarrollo de rigidez del hombro en todos los planos (limitada tanto la movilidad activa como la pasiva). Es un proceso autorresolutivo pero puede durar de 6 meses a más de 2 años. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_31',type:'mc',diff:'medium',sub:'cirugia',text:'¿Con qué enfermedad sistémica se asocia especialmente la capsulitis adhesiva?',opts:['Artritis reumatoide','Diabetes mellitus','Lupus eritematoso sistémico','Gota'],ans:1,exp:'<b>Corre :</b> La capsulitis adhesiva puede asociarse a procesos sistémicos, especialmente diabetes mellitus, o ser idiopática. Es especialmente frecuente en mujeres en torno a los 50 años. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_32',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué son las lesiones SLAP del hombro?',opts:['Roturas del tendón subescapular en su porción lateral','Lesiones del labrum desde su zona anterosuperior hasta la posterosuperior en torno a la inserción de la porción larga del bíceps','Lesiones del ligamento glenohumeral superior y anterior','Desgarros de la porción larga del bíceps en el surco bicipital'],ans:1,exp:'<b>Corre :</b> Las lesiones SLAP (Superior Labrum from Anterior to Posterior) son lesiones del labrum glenoideo desde su zona anterosuperior hasta la posterosuperior, en torno a la inserción de la porción larga del bíceps. Ocurren en deportistas jóvenes (nadadores, lanzadores). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_33',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué produce la rotura de la porción larga del bíceps y qué deformidad característica causa?',opts:['Parálisis del bíceps completa sin deformidad','Deformidad visible con músculo acortado llamada "caída de la bola bicipital"','Dolor al intentar la supinación sin deformidad','Incapacidad completa para la flexión del codo'],ans:1,exp:'<b>Corre :</b> La rotura de la porción larga del bíceps (habitualmente degenerativa) provoca la llamada "caída de la bola bicipital": el vientre muscular se retrae y produce una deformidad visible con el músculo acortado. En jóvenes se prefiere la reinserción quirúrgica; en ancianos, tratamiento conservador. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_34',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es la epicondilitis y qué la diferencia de la compresión del nervio interóseo posterior?',opts:['Son sinónimos clínicos','La epicondilitis es inflamación en la inserción de extensores-supinadores del epicóndilo; la compresión del NIP en la arcada de Frohse produce paresia extensora, no solo dolor','La compresión del NIP produce solo dolor sin déficit motor','La epicondilitis cursa con déficit sensitivo y motor'],ans:1,exp:'<b>Corre :</b> La epicondilitis (codo de tenista) es un cuadro inflamatorio en la inserción común de la musculatura extensora-supinadora. Debe diferenciarse de la compresión del nervio interóseo posterior en la arcada de Frohse del supinador, que puede producir paresia de extensores (no solo dolor). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_35',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la epitrocleítis y qué músculos están afectados?',opts:['Inflamación de la inserción de los extensores en el epicóndilo','Inflamación de la inserción de los flexores-pronadores en la epitróclea (codo de golf)','Bursitis del olécranon','Tendinitis del tríceps en su inserción en el olécranon'],ans:1,exp:'<b>Corre :</b> La epitrocleítis (codo de golf) afecta a la inserción común proximal de la musculatura flexora-pronadora en la epitróclea. Se diferencia de la epicondilitis en que el dolor se localiza en la cara medial del codo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_36',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la bursitis olecraniana y cómo se trata?',opts:['Inflamación del tendón tricipital que requiere cirugía urgente','Bursitis del olécranon (codo de estudiante) generalmente autorresolutiva que solo requiere tratamiento sintomático','Fractura de olécranon que simula bursitis','Tenosinovitis estenosante del extensor del codo'],ans:1,exp:'<b>Corre :</b> La bursitis olecraniana (codo de estudiante) es un cuadro generalmente autorresolutivo que solo requiere tratamiento sintomático (AINE, reposo). Solo en casos recidivantes o infectados se considera la extirpación de la bursa. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_37',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es la tenosinovitis estenosante de De Quervain y cuál es su test diagnóstico?',opts:['Inflamación del extensor largo del pulgar; test de Watson','Inflamación de la vaina del extensor corto y abdu r largo del pulgar a su paso por la estiloides radial; test de Finkelstein','Inflamación del flexor radial del carpo; maniobra de Phalen','Compresión del nervio mediano; test de Tinel'],ans:1,exp:'<b>Corre :</b> La tenosinovitis estenosante de De Quervain es una inflamación de la vaina común del extensor corto y separador largo del pulgar a su paso sobre la estiloides radial. El test de Finkelstein (dolor al desviar cubitalmente la muñeca con el pulgar sujeto en la palma) es el test diagnóstico. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_38',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué son los gangliones y cuál es su localización más frecuente?',opts:['Tumores benignos del nervio digital','Dilataciones de la sinovial articular o tendinosa que se "hernian"; más frecuentes en el dorso de la muñeca','Quistes epidermoides subungueales','Lipomas de la vaina tendinosa'],ans:1,exp:'<b>Corre :</b> Los gangliones son dilataciones de la sinovial articular o tendinosa que se "hernian" a través de cápsulas articulares y vainas. Son especialmente frecuentes en el dorso de la muñeca. De consistencia elástica, su tamaño varía con el tiempo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_39',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la "rodilla de beata" y cuál es su causa?',opts:['Bursitis prerrotuliana por presión crónica en la cara anterior de la rodilla','Tendinitis del cuádriceps por uso excesivo','Bursitis de la pata de ganso en la cara medial de la tibia','Síndrome de rozamiento de la bandeleta iliotibial'],ans:0,exp:'<b>Corre :</b> La bursitis prerrotuliana o "rodilla de beata" se produce por presión crónica y repetida en la cara anterior de la rodilla (como al arrodillarse). Provoca dolor y tumefacción en la cara anterior de la rodilla. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_40',type:'mc',diff:'medium',sub:'cirugia',text:'Si un paciente tiene rotura del tendón del cuádriceps, ¿cómo aparece la rótula en la radiografía lateral?',opts:['Rótula en posición normal','Rótula "descendida" (baja)','Rótula "ascendida" (alta)','Rótula en posición lateral'],ans:1,exp:'<b>Corre :</b> Si se rompe el tendón del cuádriceps, la rótula se "cae" (desciende) en la radiografía de rodilla en proyección lateral, al no existir tracción superior. Si se rompe el tendón rotuliano, la rótula "asciende". En ambos casos se requiere cirugía. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_41',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es el quiste de Baker y en qué se diferencia en el niño y en el adulto?',opts:['Es igual en niños y adultos; siempre requiere extirpación quirúrgica','En el niño es indoloro y autorresolutivo; en el adulto es secundario a patología intraarticular (lesión meniscal, artrosis, AR) y lo fundamental es tratar la patología responsable','Es una complicación exclusiva de la artritis reumatoide','Siempre se rompe espontáneamente y produce tromboflebitis'],ans:1,exp:'<b>Corre :</b> El quiste de Baker es una dilatación de la bolsa serosa del semimembranoso. En el niño es indoloro y autorresolutivo. En el adulto es secundario a patología intraarticular y lo fundamental es identificar y tratar la causa (no extirpar solo el quiste). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_42',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la causa más frecuente de talalgia plantar?',opts:['Artritis gotosa del tobillo','Fractura de estrés del calcáneo','Fascitis plantar (irritación mecánica de la fascia plantar)','Bursitis retrocalcánea'],ans:2,exp:'<b>Corre :</b> Una de las causas más frecuentes de dolor en el retropié (talalgia) es la inflamación o irritación mecánica de la fascia plantar (fascitis plantar). El espolón calcáneo es una prominencia ósea que se forma como respuesta pero no es la causa del dolor. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_43',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la enfermedad de Dupuytren?',opts:['Tenosinovitis estenosante del flexor del anular y meñique','Proceso caracterizado por el desarrollo de fibrosis de la fascia palmar con retracción de los dedos (anular y meñique principalmente)','Rotura espontánea del tendón flexor del pulgar','Calcificación de los tendones extensores de la mano'],ans:1,exp:'<b>Corre :</b> La enfermedad de Dupuytren es un proceso caracterizado por el desarrollo de fibrosis y contractura de la fascia palmar, produciendo retracción progresiva de los dedos (principalmente el anular y el meñique) hacia la palma. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_44',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de elección de la enfermedad de Dupuytren cuando la contractura limita la función?',opts:['Inyección de corticoides local','Fasciotomía percutánea exclusivamente','Fasciotomía o fascie mía quirúrgica con posible injerto cutáneo','Fisioterapia exclusivamente'],ans:2,exp:'<b>Corre :</b> El tratamiento de la enfermedad de Dupuytren sintomática es quirúrgico: fasciotomía o fascie mía. En casos graves puede ser necesario un injerto cutáneo (técnica de McCash o dermofascie mía). La fasciotomía percutánea tiene alta tasa de recidiva. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_45',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la lesión más frecuente del ligamento cruzado anterior (LCA)?',opts:['Rotura parcial en su porción posterior','Rotura completa del LCA por mecanismo de valgo-rotación o hiperextensión en deportes de pivote','Avulsión de la espina tibial en adultos','Lesión aislada sin otras lesiones asociadas siempre'],ans:1,exp:'<b>Corre :</b> La rotura del LCA es la lesión ligamentosa más frecuente de la rodilla en deportistas. Se produce habitualmente por mecanismo de valgo-rotación externa o de hiperextensión, sin conta  dire . Es frecuente la asociación con lesiones meniscales. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_46',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la maniobra de exploración del LCA y en qué posición se realiza?',opts:['Cajón posterior en flexión de 90°','Maniobra de Lachman: cajón anterior en flexión de 30°','Varo-valgo forzado en extensión completa','Test de McMurray para menisco'],ans:1,exp:'<b>Corre :</b> La maniobra de Lachman consiste en forzar un cajón anterior con la rodilla en flexión de 30°, y se emplea en la exploración del ligamento cruzado anterior. Es la maniobra más sensible para diagnosticar la rotura del LCA. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_47',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de la rotura del LCA en un deportista joven que desea reanudar su actividad?',opts:['Inmovilización con yeso 6 semanas','Rehabilitación exclusiva sin cirugía','Reconstrucción ligamentosa artroscópica con plastia tendinosa (tercio central del tendón rotuliano o tendones de la pata de ganso)','Artrodesis de rodilla'],ans:2,exp:'<b>Corre :</b> En el deportista joven con inestabilidad que desea reanudar su actividad, está indicada la reconstrucción ligamentosa artroscópica con plastia tendinosa propia (tercio central del tendón rotuliano o tendones de la pata de ganso) o aloinjerto criopreservado. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_48',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué lesión meniscal es la más frecuente?',opts:['Rotura del menisco lateral en asa de cubo','Rotura del menisco medial (interno) en asa de cubo','Rotura radial del menisco medial','Rotura degenerativa del menisco lateral'],ans:1,exp:'<b>Corre :</b> La rotura del menisco medial (interno) es la más frecuente, generalmente en su porción posterior. La rotura "en asa de cubo" (el fragmento se desplaza hacia el interior de la articulación) puede bloquear la rodilla en flexión. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_49',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la prueba complementaria de elección para diagnosticar las lesiones meniscales?',opts:['Radiografía de rodilla en carga','Artroscopia diagnóstica','RMN de rodilla','Ecografía de partes blandas'],ans:2,exp:'<b>Corre :</b> La RMN de rodilla es la prueba complementaria de elección para diagnosticar las lesiones meniscales, con alta sensibilidad y especificidad. La artroscopia es el gold standard pero es invasiva y tiene indicación terapéutica además de diagnóstica. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_50',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el plexo nervioso que inerva el miembro superior?',opts:['Plexo lumbar','Plexo sacro','Plexo braquial (C5-T1)','Plexo cervical (C1-C4)'],ans:2,exp:'<b>Corre :</b> El plexo braquial (raíces C5-T1) es el plexo nervioso que inerva el miembro superior. Se forma a partir de las ramas anteriores de los nervios espinales de C5 a T1. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_51',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la clasificación de las lesiones nerviosas periféricas de Seddon?',opts:['Axonotmesis, neuropraxia y neurotmesis','Neuropraxia (solo bloqueo de conducción), axonotmesis (lesión axonal con continuidad del epineuro) y neurotmesis (sección completa)','Lesión grado I, II y III','Lesión leve, moderada y grave'],ans:1,exp:'<b>Corre :</b> La clasificación de Seddon divide las lesiones nerviosas en: neuropraxia (bloqueo de conducción sin daño axonal; pronóstico excelente), axonotmesis (lesión axonal con epineuro íntegro; puede regenerar) y neurotmesis (sección completa; requiere cirugía). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_52',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuánto regenera aproximadamente el nervio periférico por día tras una lesión?',opts:['0,1-0,5 mm/día','1 mm/día','5 mm/día','10 mm/día'],ans:1,exp:'<b>Corre :</b> Los nervios periféricos regeneran a una velocidad aproximada de 1 mm/día (1 cm/mes). Esto es importante para calcular el tiempo de recuperación esperado en función de la distancia entre el lugar de la lesión y el órgano diana. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_53',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué es la parálisis obstétrica de Erb-Duchenne y qué raíces afecta?',opts:['Afecta a C8-T1; produce mano en garra','Afecta a C5-C6; produce el brazo en rotación interna, codo en extensión y antebrazo en pronación (postura de "propina")','Afecta a todo el plexo C5-T1; produce parálisis completa del miembro superior','Afecta a C7; produce parálisis del tríceps'],ans:1,exp:'<b>Corre :</b> La parálisis obstétrica de Erb-Duchenne afecta a las raíces C5-C6 y produce el brazo en rotación interna, codo en extensión y antebrazo en pronación (postura de "propina" o del camarero). Se produce por tracción de la cabeza durante el parto. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_54',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué raíces afecta la parálisis obstétrica de Klumpke y qué déficit produce?',opts:['C5-C6; parálisis del deltoides y bíceps','C8-T1; parálisis de la musculatura intrínseca de la mano con síndrome de Horner asociado','C7; parálisis del tríceps aislada','C5-C7; parálisis del hombro completa'],ans:1,exp:'<b>Corre :</b> La parálisis de Klumpke afecta a las raíces C8-T1 (fascículo inferior del plexo braquial). Produce parálisis de la musculatura intrínseca de la mano (mano en garra) y puede asociarse a síndrome de Horner por afectación de las fibras simpáticas de T1. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_55',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué mecanismo produce lesión del fascículo superior del plexo braquial (C5-C6)?',opts:['Hiperabducción (raíces inferiores, C8 y D1)','Traumatismo de alta velocidad que separa la cabeza del hombro (tracción cabeza-hombro); afecta raíces superiores C5-C6','Fractura de la primera costilla','Compresión por tumor de Pancoast'],ans:1,exp:'<b>Corre :</b> Los mecanismos que producen lesión del fascículo superior (C5-C6) son los que separan cabeza y hombro, como la caída sobre el hombro o la tracción durante el parto (parálisis de Erb). La hiperabducción afecta preferentemente a las raíces inferiores (C8-D1). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_56',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el signo clínico que indica avulsión radicular (mal pronóstico) en las lesiones del plexo braquial?',opts:['Signo de Tinel positivo en cuello','Síndrome de Horner (ptosis, miosis, anhidrosis)','Reflejo bicipital abolido','Parálisis del deltoides aislada'],ans:1,exp:'<b>Corre :</b> El síndrome de Horner (ptosis, miosis, anhidrosis ipsilateral) indica avulsión de la raíz T1 con lesión de las fibras simpáticas cervicales, lo que representa un signo de muy mal pronóstico en las lesiones del plexo braquial. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_57',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el nervio más frecuentemente atrapado en el síndrome del túnel carpiano?',opts:['Nervio cubital','Nervio radial','Nervio mediano','Nervio interóseo anterior'],ans:2,exp:'<b>Corre :</b> El síndrome del túnel carpiano es la neuropatía por atrapamiento más frecuente y afecta al nervio mediano a su paso bajo el ligamento transverso del carpo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_58',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué músculos inerva el nervio mediano en la mano?',opts:['Todos los interóseos y el adu r del pulgar','Músculos de la eminencia hipotenar','Músculos de la eminencia tenar (abdu r corto, oponente, flexor corto superficial del pulgar) y los dos lumbricales radiales','Todos los lumbricales y los interóseos dorsales'],ans:2,exp:'<b>Corre :</b> El nervio mediano inerva en la mano los músculos de la eminencia tenar (abdu r corto del pulgar, oponente del pulgar, cabeza superficial del flexor corto del pulgar) y los dos lumbricales radiales. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_59',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la deformidad típica de la mano por lesión del nervio cubital a nivel de la muñeca?',opts:['Mano en gota','Mano en garra del anular y meñique (con hiperextensión MCF y flexión IF)','Pulgar en adducción irreductible','Mano caída con pérdida de extensión de todos los dedos'],ans:1,exp:'<b>Corre :</b> La lesión del nervio cubital produce mano en garra del anular y meñique (hipercorrección MCF por parálisis de los lumbricales cubitales e hiperflexión IF por acción de los flexores). Los dos primeros dedos están menos afectados (paradoja cubital). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_60',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué produce la lesión del nervio radial a nivel del codo o antebrazo?',opts:['Pérdida de la sensibilidad de toda la mano','Mano caída (wrist drop) con incapacidad para extender la muñeca y los dedos','Parálisis del tríceps con incapacidad para extender el codo','Parálisis del bíceps con incapacidad para flexionar el codo'],ans:1,exp:'<b>Corre :</b> La lesión del nervio radial a nivel del antebrazo produce parálisis de la extensión de la muñeca y de los dedos (mano caída o wrist drop). Si la lesión es alta (axila), también hay parálisis del tríceps. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_61',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es el síndrome del desfiladero torácico?',opts:['Compresión del plexo braquial, arteria y vena subclavia a su paso entre las estructuras del cuello y la axila','Compresión del nervio frénico por costilla cervical','Compresión del nervio espinal accesorio en el triángulo posterior del cuello','Estenosis del canal espinal cervical'],ans:0,exp:'<b>Corre :</b> El síndrome del desfiladero torácico (o síndrome de salida torácica) es la compresión del plexo braquial, arteria y/o vena subclavia a su paso entre las estructuras del cuello y la axila (costilla cervical, músculo escaleno, clavícula, etc.). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_62',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es la meralgia parestésica y qué nervio afecta?',opts:['Dolor en la cara medial del muslo por compresión del nervio obturador','Parestesias en la cara anterolateral del muslo por compresión del nervio cutáneo lateral femoral (nervio femorocutáneo) bajo el ligamento inguinal','Dolor irradiado por el nervio ciático','Compresión del nervio femoral en el canal del adu r'],ans:1,exp:'<b>Corre :</b> La meralgia parestésica consiste en parestesias y dolor en la cara anterolateral del muslo producidas por compresión del nervio cutáneo lateral del muslo (femorocutáneo) a su paso bajo el ligamento inguinal. Se asocia a obesidad y embarazo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_63',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la lesión nerviosa periférica más frecuente en el miembro inferior?',opts:['Lesión del nervio femoral','Lesión del nervio ciático','Síndrome del túnel tarsiano','Neuropatía del nervio peroneo a nivel del cuello del peroné'],ans:3,exp:'<b>Corre :</b> La lesión del nervio peroneo a nivel del cuello del peroné es la neuropatía periférica más frecuente del miembro inferior. Produce pie caído (parálisis de la dorsiflexión del pie) y anestesia en el dorso del pie. Se produce por presión directa o por fracturas proximales del peroné. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_64',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la diferencia clínica entre la lesión del nervio peroneo común y la del nervio tibial posterior?',opts:['Son indistinguibles clínicamente','Lesión del peroneo: pie caído y anestesia dorsal del pie; lesión del tibial: pie equino con pérdida de flexión plantar y anestesia plantar','Lesión del peroneo: pie equino; lesión del tibial: pie caído','Solo se diferencia por electromiografía'],ans:1,exp:'<b>Corre :</b> La lesión del nervio peroneo común produce pie caído (parálisis de dorsiflexión) y anestesia en dorso del pie. La lesión del nervio tibial posterior produce pérdida de la flexión plantar y de los movimientos del pie, con anestesia en la planta. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_65',type:'mc',diff:'hard',sub:'cirugia',text:'¿Qué estudio complementario es de elección para el diagnóstico de las lesiones nerviosas periféricas?',opts:['RMN de la extremidad afectada','Electromiografía (EMG) y velocidad de conducción nerviosa (VCN)','TC de la extremidad','Ecografía nerviosa exclusivamente'],ans:1,exp:'<b>Corre :</b> La electromiografía (EMG) y la velocidad de conducción nerviosa (VCN) son los estudios complementarios de elección para diagnosticar y caracterizar las lesiones nerviosas periféricas, permitiendo además monitorizar la recuperación. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_66',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuáles son las indicaciones de cirugía primaria en las lesiones del plexo braquial?',opts:['Siempre, en las primeras 24 horas','Nunca, siempre tratamiento conservador inicial','En lesiones abiertas con sección completa del nervio; en lesiones cerradas generalmente se espera 3-6 meses para valorar la recuperación espontánea','Solo si hay avulsión radicular confirmada'],ans:2,exp:'<b>Corre :</b> En lesiones abiertas con sección nerviosa completa, la cirugía primaria está indicada. En lesiones cerradas del plexo braquial se espera habitualmente 3-6 meses para valorar la recuperación espontánea antes de indicar cirugía. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_67',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de la lesión del ligamento cruzado posterior (LCP)?',opts:['Siempre quirúrgico de forma inmediata','En la mayoría de los casos tratamiento conservador con rehabilitación; solo cirugía en inestabilidades graves o lesiones combinadas','Igual que el LCA, siempre reconstrucción artroscópica','Inmovilización con yeso 6 semanas seguida de fisioterapia'],ans:1,exp:'<b>Corre :</b> La mayoría de las roturas del LCP aisladas se tratan de forma conservadora con rehabilitación intensa. La cirugía está indicada en inestabilidades posteriores graves, lesiones combinadas o fracaso del tratamiento conservador. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_68',type:'mc',diff:'easy',sub:'cirugia',text:'¿En qué consiste la inestabilidad posterolateral de rodilla?',opts:['Inestabilidad solo en valgo forzado','Inestabilidad posterior asociada a lesión de ligamento colateral lateral, cápsula posterolateral y tendón poplíteo; con aumento de la rotación externa pasiva y cajón posterolateral','Inestabilidad anterior y posterior sin lesión de estructuras laterales','Inestabilidad en todos los planos por lesión de los cuatro ligamentos'],ans:1,exp:'<b>Corre :</b> La inestabilidad posterolateral se produce cuando la inestabilidad posterior del LCP se asocia a lesión de estructuras laterales (LCL, cápsula posterolateral, tendón poplíteo, bíceps). Se aprecia aumento de rotación externa pasiva y cajón posterolateral. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_69',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el diagnóstico diferencial del esguince de tobillo con una fractura de tobillo?',opts:['No es posible diferenciarlo sin radiografía','En el esguince: periodo de latencia asintomático inicial, luego dolor continuo; en la fractura: dolor continuo desde el accidente sin periodo de latencia','En la fractura: el dolor cede con el reposo; en el esguince: dolor continuo','Son clínicamente indistinguibles'],ans:1,exp:'<b>Corre :</b> En el esguince de tobillo, el paciente refiere dolor brusco que casi desaparece y aumenta horas más tarde (periodo de latencia). En las fracturas de tobillo, el dolor es continuo desde el accidente sin periodo de latencia asintomático. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_70',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué lesión se denomina "codo de niñera" y cuál es su mecanismo?',opts:['Fractura supracondílea por caída sobre la mano','Subluxación de la cabeza radial por tracción brusca del antebrazo en el niño pequeño','Luxación de codo por hiperextensión','Fractura de olécranon por caída directa'],ans:1,exp:'<b>Corre :</b> El "codo de niñera" (pronación dolorosa) es la subluxación de la cabeza radial que se produce por tracción brusca del antebrazo en pronación en el niño pequeño (cuando el adulto tira del niño de la mano). Requiere reducción por supinación y flexión del codo. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_71',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de la luxación de rótula aguda?',opts:['Cirugía inmediata en todos los casos','Reducción inmediata (extensión de la rodilla con presión medial sobre la rótula) seguida de inmovilización y rehabilitación','Artrodesis de la articulación femororrotuliana','Patele mía inmediata'],ans:1,exp:'<b>Corre :</b> El tratamiento de la luxación aguda de rótula consiste en la reducción inmediata (extendiendo la rodilla y aplicando presión medial sobre la rótula), seguida de inmovilización y rehabilitación. La cirugía se indica en luxaciones recidivantes. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_72',type:'mc',diff:'hard',sub:'cirugia',text:'¿Qué estructuras del complejo ligamentoso medial de la rodilla son responsables de la estabilidad frente al valgo forzado?',opts:['Ligamento cruzado anterior y posterior','Ligamento colateral medial (LCM), la cápsula posteromedial y el tendón del semimembranoso','Ligamento patelofemoral medial y tendón del vasto medial','Ligamento poplíteo arcuato y tendón del poplíteo'],ans:1,exp:'<b>Corre :</b> La estabilidad frente al valgo forzado de rodilla depende principalmente del ligamento colateral medial (LCM), la cápsula posteromedial y el tendón del semimembranoso. El LCA también contribuye en extensión. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_73',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la estructura comprometida en la luxación de rodilla con mayor riesgo de amputación si no se trata?',opts:['Nervio peroneo','Arteria poplítea (lesión vascular)','Tendón cuadricipital','Nervio ciático'],ans:1,exp:'<b>Corre :</b> La arteria poplítea puede lesionarse en la luxación de rodilla, comprometiendo la irrigación del pie. Si la isquemia no se trata de urgencia (revascularización), puede llegar a ser necesaria la amputación. Es la complicación más grave de la luxación de rodilla. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_74',type:'mc',diff:'medium',sub:'cirugia',text:'¿Con qué frecuencia son bilaterales las luxaciones de cadera?',opts:['Nunca son bilaterales','Raramente (<5%)','En aproximadamente el 10-15% de los casos','Siempre son bilaterales en accidentes de tráfico'],ans:1,exp:'<b>Corre :</b> Las luxaciones de cadera bilaterales son raras (<5%), aunque pueden producirse en traumatismos de alta energía con impa  simultáneo en ambas rodillas contra el tablero del salpicadero. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_75',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué signo de exploración diferencia el esguince de 3.er grado (completo) del de 2.º grado en tobillo?',opts:['Signo de Tinel en traye  peroneal','Bostezamiento articular (apertura del espacio articular) con maniobra de inversión forzada (estrés de inversión)','Test de Thompson positivo','Signo de Dupuytren positivo'],ans:1,exp:'<b>Corre :</b> El bostezamiento articular (apertura anormal del espacio articular con maniobra de estrés en inversión o de cajón anterior) diferencia el esguince completo (grado III) del parcial. Se puede confirmar con radiografía en estrés. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_76',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es la estructura cuya rotura provoca el "cajón anterior" de tobillo?',opts:['Ligamento peroneocalcáneo','Ligamento peroneoastragalino anterior','Ligamento deltoideo','Ligamento interóseo tibioperoneal'],ans:1,exp:'<b>Corre :</b> La rotura del ligamento peroneoastragalino anterior es la que produce el cajón anterior de tobillo (desplazamiento anterior del astrágalo bajo la mortaja tibial). Es el ligamento lateral del tobillo que se lesiona primero. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_77',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuáles son las tres causas más frecuentes de hombro doloroso que deben diferenciarse?',opts:['Artrosis, artritis reumatoide y fracturas','Síndrome subacromial, capsulitis adhesiva y tendinitis calcificante','Rotura del bíceps, artritis séptica y luxación crónica','Luxación posterior, SLAP y artrosis'],ans:1,exp:'<b>Corre :</b> Entre los procesos de partes blandas del hombro que producen hombro doloroso, los más frecuentes son el síndrome de rozamiento subacromial (con o sin rotura del manguito), la capsulitis adhesiva y la tendinitis calcificante. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_78',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuántas infiltraciones con corticoides y anestésicos en el espacio subacromial se pueden realizar en el síndrome de rozamiento?',opts:['Solo 1 en toda la vida del paciente','Entre 1 y 3','Tantas como sean necesarias sin límite','Se contraindican por causar rotura del manguito'],ans:1,exp:'<b>Corre :</b> En pacientes con dolor muy intenso o que no responden al tratamiento conservador inicial, pueden realizarse entre una y tres infiltraciones con corticoides y anestésicos en el espacio subacromial. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_79',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuánto tiempo debe durar el tratamiento conservador del síndrome de rozamiento subacromial antes de indicar cirugía?',opts:['1-2 semanas','1-2 meses','3-6 meses','12 meses mínimo'],ans:2,exp:'<b>Corre :</b> El tratamiento quirúrgico del síndrome de rozamiento subacromial está indicado en aquellos pacientes que no responden al tratamiento conservador correctamente realizado durante 3-6 meses, o en pacientes jóvenes con rotura aguda del manguito. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_80',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el fa r pronóstico más importante para el éxito de la sutura del manguito de los rotadores?',opts:['Edad del paciente','Presencia de bursitis subacromial asociada','Tamaño de la lesión del manguito','Grado de atrofia muscular en la RMN'],ans:2,exp:'<b>Corre :</b> El fa r pronóstico más importante para el éxito de la sutura del manguito de los rotadores es el tamaño de la lesión. Las roturas muy extensas pueden ser irreconstruibles y requerir desbridamiento o transferencias tendinosas. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_81',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué diferencia principal existe entre la epicondilitis y la epitrocleítis?',opts:['La epicondilitis es del lado cubital y la epitrocleítis del radial','La epicondilitis afecta a la inserción de los extensores-supinadores en el epicóndilo lateral; la epitrocleítis afecta a los flexores-pronadores en la epitróclea medial','Son la misma entidad con diferente localización','La epitrocleítis siempre requiere cirugía; la epicondilitis no'],ans:1,exp:'<b>Corre :</b> La epicondilitis (codo de tenista) afecta a la inserción de los extensores-supinadores en el epicóndilo lateral. La epitrocleítis (codo de golf) afecta a la inserción de los flexores-pronadores en la epitróclea medial. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_82',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la articulación más frecuentemente luxada del cuerpo humano?',opts:['Cadera','Hombro (glenohumeral)','Codo','Rodilla'],ans:1,exp:'<b>Corre :</b> El hombro (articulación glenohumeral) es la articulación más frecuentemente luxada del cuerpo humano, por su diseño que prioriza la movilidad sobre la estabilidad (glenoides poco profunda, gran cabeza humeral). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_83',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué lesión ósea de la glenoides es característica de la luxación anterior recidivante?',opts:['Fractura de Hill-Sachs posterior','Lesión de Bankart ósea (fractura de la glenoides anteroinferior)','Fractura de la tuberosidad mayor','Osteólisis del acromion'],ans:1,exp:'<b>Corre :</b> La lesión de Bankart ósea (fractura del borde anteroinferior de la glenoides) es característica de la luxación glenohumeral anterior recidivante. Junto con la lesión de Hill-Sachs (en la cabeza humeral), contribuye a la inestabilidad recidivante. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_84',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento inicial de la luxación glenohumeral aguda?',opts:['Cirugía inmediata','Reducción cerrada bajo anestesia/sedación lo antes posible','Inmovilización con cabestrillo sin reducción','Artroscopia diagnóstica urgente'],ans:1,exp:'<b>Corre :</b> El tratamiento de la luxación glenohumeral aguda es la reducción cerrada lo antes posible, generalmente con analgesia o sedación. Existen múltiples técnicas de reducción (Cunningham, Stimson, Milch, etc.). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_85',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué complicación puede producirse en el quiste de Baker del adulto, simulando una tromboflebitis?',opts:['Infección bacteriana del quiste','Rotura espontánea del quiste con salida de líquido sinovial al compartimento posterior de la pierna','Compresión de la arteria poplítea','Calcificación del quiste'],ans:1,exp:'<b>Corre :</b> En ocasiones (especialmente en AR), el quiste de Baker se rompe espontáneamente, produciéndose un cuadro que simula tromboflebitis (dolor, rubor e hinchazón del gemelo). Esta sintomatología cede con elevación del miembro, reposo, calor local y AINE. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_86',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la indicación de la fasciotomía percutánea en la enfermedad de Dupuytren?',opts:['Primera opción en todos los pacientes','Pacientes jóvenes con enfermedad extensa','Solo en recidivas tras fascie mía previa','Pacientes ancianos con mal estado general como opción menos agresiva (alta tasa de recidiva)'],ans:3,exp:'<b>Corre :</b> La fasciotomía percutánea en la enfermedad de Dupuytren se considera indicada principalmente en pacientes ancianos con mal estado general que no pueden ser sometidos a cirugía mayor, aunque tiene tasas muy elevadas de recidiva. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_87',type:'mc',diff:'hard',sub:'cirugia',text:'¿Qué es la dermofascie mía en la enfermedad de Dupuytren y cuándo está indicada?',opts:['Fascie mía mínima sin resección cutánea; indicada siempre','Resección de la fascia y la piel suprayacente con cobertura mediante injerto cutáneo; indicada en recidivas o diátesis de Dupuytren','Infiltración de colagenasa; indicada como primera opción','Fasciotomía percutánea ampliada; indicada en enfermedad moderada'],ans:1,exp:'<b>Corre :</b> La dermofascie mía consiste en la resección de la fascia y de la piel suprayacente, seguida de cobertura con injerto cutáneo de espesor parcial. Está indicada en pacientes con recidiva de Dupuytren o con diátesis de Dupuytren (tendencia a recidivar). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_88',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es la prueba de imagen más útil para valorar la extensión de la lesión del manguito antes de la cirugía?',opts:['Radiografía simple anteroposterior','Artro-TC','Ecografía o RMN (valorar extensión y atrofia muscular)','Gammagrafía ósea'],ans:2,exp:'<b>Corre :</b> Para planificar la cirugía del manguito, se emplea la ecografía (más disponible y barata) o la RMN (más completa, permite valorar atrofia muscular y lesiones asociadas). La RMN es preferible cuando se necesita evaluar la extensión con precisión. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_89',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué produce el signo del "surco" (sulcus sign) en la exploración del hombro?',opts:['Rotura del supraespinoso','Inestabilidad inferior glenohumeral (laxitud del ligamento glenohumeral inferior)','Capsulitis adhesiva','Lesión SLAP'],ans:1,exp:'<b>Corre :</b> El signo del surco (sulcus sign) consiste en la aparición de un surco visible entre el acromion y la cabeza humeral al traccionar el brazo hacia abajo, indicando inestabilidad inferior glenohumeral por laxitud del ligamento glenohumeral inferior. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_90',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tipo de meniscopatía más frecuente en el anciano?',opts:['Rotura traumática aguda en asa de cubo','Rotura del ligamento cruzado anterior asociada','Rotura degenerativa del menisco medial (horizontal o compleja)','Quiste meniscal lateral'],ans:2,exp:'<b>Corre :</b> En el paciente anciano, las roturas meniscales son predominantemente degenerativas, afectando más frecuentemente al menisco medial (interno) con patrones horizontales o complejos. El tratamiento es menos agresivo que en el deportista joven. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_91',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el nervio que puede lesionarse en la luxación de hombro anterior y cuya lesión produce anestesia en "charretera"?',opts:['Nervio radial','Nervio axilar (circunflejo)','Nervio musculocutáneo','Nervio supraescapular'],ans:1,exp:'<b>Corre :</b> El nervio axilar (circunflejo) puede lesionarse en la luxación glenohumeral anterior. Además de parálisis del deltoides, produce anestesia en la zona lateral del hombro (área del "parche" o "charretera"). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_92',type:'mc',diff:'easy',sub:'cirugia',text:'¿Cuál es el tratamiento de la tendinitis calcificante del hombro cuando los síntomas no ceden?',opts:['Cirugía abierta con exéresis de la clavícula distal','Artroscopia con resección de la calcificación (acromioplastia + extirpación del depósito)','Solo infiltraciones repetidas de corticoides','Radioterapia local'],ans:1,exp:'<b>Corre :</b> En los casos poco frecuentes de tendinitis calcificante refractaria, el tratamiento consiste en resecar la calcificación, preferentemente por vía artroscópica (con acromioplastia asociada si es necesario). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_93',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué mecanismo de producción tiene la lesión del ligamento cruzado posterior (LCP)?',opts:['Valgo-rotación externa sin conta ','Hiperflexión o traumatismo dire  sobre la tibia proximal en flexión (dashboard injury)','Hiperextensión brusca del miembro inferior','Inversión forzada del tobillo'],ans:1,exp:'<b>Corre :</b> El ligamento cruzado posterior (LCP) se lesiona típicamente por hiperflexión de la rodilla o por traumatismo dire  sobre la tibia proximal en flexión (como impa  sobre el tablero del salpicadero en un accidente de tráfico). <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_94',type:'mc',diff:'hard',sub:'cirugia',text:'¿Qué es la "paradoja cubital" en la lesión del nervio cubital?',opts:['Que la lesión alta del cubital produce mayor deformidad en garra que la lesión baja','Que la lesión alta produce menor deformidad en garra que la lesión baja (porque los flexores profundos del anular y meñique también están paralizados)','Que el cubital no tiene función sensitiva','Que el cubital inerva el lado radial de la mano'],ans:1,exp:'<b>Corre :</b> La paradoja cubital indica que cuanto más alta es la lesión del nervio cubital, menor es la deformidad en garra, porque al paralizarse también los flexores profundos del anular y meñique (también cubitales), no hay fuerza que lleve los dedos a la flexión interfalángica. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_95',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es el test de Thompson y qué lesión diagnostica?',opts:['Compresión del gemelo; diagnóstica la rotura del tendón de Aquiles','Tracción del tobillo; diagnóstica la fractura de calcáneo','Presión en el hueco poplíteo; diagnóstica la rotura del LCP','Rotación interna del pie; diagnóstica la luxación subastragalina'],ans:0,exp:'<b>Corre :</b> El test de Thompson consiste en comprimir el gemelo con el paciente en decúbito prono. Si el tendón de Aquiles está íntegro, el pie realiza una flexión plantar. Si el test es positivo (no hay movimiento del pie), indica rotura completa del tendón de Aquiles. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_96',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué tratamiento está indicado en la rotura aguda del tendón de Aquiles en deportistas jóvenes?',opts:['Siempre conservador con yeso en equino','Tratamiento quirúrgico (sutura tendinosa) seguido de rehabilitación','Ortesis funcional con carga inmediata','Inyección de plasma rico en plaquetas'],ans:1,exp:'<b>Corre :</b> En deportistas jóvenes y activos, la rotura aguda del tendón de Aquiles se trata preferentemente con cirugía (sutura tendinosa), ya que reduce la tasa de re-rotura y permite una rehabilitación más rápida. En pacientes menos activos o mayores puede optarse por tratamiento conservador. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_97',type:'mc',diff:'easy',sub:'cirugia',text:'¿Qué maniobra se usa para explorar el menisco medial en la rodilla?',opts:['Maniobra de Lachman','Maniobra de McMurray (flexión máxima + rotación + extensión con dolor o clic en la cara medial)','Cajón posterior a 90°','Test de Thomson'],ans:1,exp:'<b>Corre :</b> La maniobra de McMurray se realiza con la rodilla en flexión máxima seguida de rotación y extensión progresiva. El dolor o chasquido en la interlínea medial es sugestivo de lesión del menisco medial; si aparece en la interlínea lateral, del menisco lateral. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_98',type:'mc',diff:'medium',sub:'cirugia',text:'¿Cuál es el tratamiento de la fasciitis plantar cuando los síntomas son rebeldes al tratamiento conservador?',opts:['Cirugía inmediata con sección de la fascia','Reposo relativo, plantillas de descarga y AINE; excepcionalmente cirugía','Radioterapia local','Infiltración con corticoides siempre como primera medida'],ans:1,exp:'<b>Corre :</b> El cuadro de fascitis plantar se trata con reposo relativo, plantillas de descarga y AINE. Es excepcional que haya que recurrir a la cirugía, ya que la mayoría responden al tratamiento conservador. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_99',type:'mc',diff:'medium',sub:'cirugia',text:'¿Qué es la artropatía del manguito (hombro de Milwaukee) y qué la produce?',opts:['Artritis inflamatoria del hombro por cristales de pirofosfato','Cambios degenerativos secundarios de la articulación glenohumeral por roturas masivas del manguito de larga evolución','Artritis séptica del hombro por Staphylococcus aureus','Artropatía neuropática del hombro por siringomielia'],ans:1,exp:'<b>Corre :</b> La artropatía del manguito (hombro de Milwaukee) son los cambios degenerativos secundarios que pueden desarrollar algunos pacientes con lesiones muy extensas del manguito y largo tiempo de evolución, que pueden requerir finalmente una artroplastia de hombro. <i>Ref:   Traumatología 10.ª ed.</i>'},
  {id:'cir2_100',type:'mc',diff:'hard',sub:'cirugia',text:'En el síndrome del desfiladero torácico, ¿qué maniobra provoca la reproducción de los síntomas por compresión de la arteria subclavia?',opts:['Test de Finkelstein','Maniobra de Adson (rotación y extensión cervical ipsilateral + inspiración profunda; disminución del pulso radial)','Signo de Tinel en el codo','Test de Phalen (flexión de muñeca mantenida)'],ans:1,exp:'<b>Corre :</b> La maniobra de Adson (rotación e hiperextensión cervical hacia el lado afectado + inspiración profunda) puede reproducir los síntomas y disminuir el pulso radial en el síndrome del desfiladero torácico por compresión de la arteria subclavia. <i>Ref:   Traumatología 10.ª ed.</i>'}
];
